// Generated by forge proof from mcp-command-queue.md
import { describe, test, expect, beforeEach, afterEach } from 'bun:test';
import { promises as fs } from 'fs';
import path from 'path';
import os from 'os';
import { isExecutorRunning } from './executor.js';
import {
  getTestDb,
  insertTask,
  claimTask,
  getTaskById,
  markStaleTasks,
  getPendingTasks,
} from './db.js';

// ── Helpers ──────────────────────────────────────────────────

let tmpDir: string;

beforeEach(async () => {
  tmpDir = await fs.mkdtemp(path.join(os.tmpdir(), 'forge-executor-test-'));
  await fs.mkdir(path.join(tmpDir, '.forge'), { recursive: true });
});

afterEach(async () => {
  await fs.rm(tmpDir, { recursive: true, force: true });
});

// ── isExecutorRunning ────────────────────────────────────────

describe('isExecutorRunning', () => {
  test('returns false when no PID file exists', async () => {
    const result = await isExecutorRunning(tmpDir);
    expect(result).toBe(false);
  });

  test('returns false for empty PID file', async () => {
    await fs.writeFile(path.join(tmpDir, '.forge', 'executor.pid'), '');
    const result = await isExecutorRunning(tmpDir);
    expect(result).toBe(false);
  });

  test('returns false for non-numeric PID file content', async () => {
    await fs.writeFile(path.join(tmpDir, '.forge', 'executor.pid'), 'not-a-pid');
    const result = await isExecutorRunning(tmpDir);
    expect(result).toBe(false);
  });

  test('returns false for a stale PID (process not running)', async () => {
    // Use a PID that is very unlikely to be running (> max PID range)
    // On most systems, PIDs wrap at 4194304 (Linux) or 99999 (macOS)
    // We use a valid-looking but dead PID: 999999
    await fs.writeFile(path.join(tmpDir, '.forge', 'executor.pid'), '999999');
    const result = await isExecutorRunning(tmpDir);
    expect(result).toBe(false);
  });

  test('returns true when PID file contains a live process PID', async () => {
    // Use the current process's PID — guaranteed to be alive
    const pidPath = path.join(tmpDir, '.forge', 'executor.pid');
    await fs.writeFile(pidPath, String(process.pid));
    const result = await isExecutorRunning(tmpDir);
    expect(result).toBe(true);
  });

  test('does not throw for non-existent directory', async () => {
    const nonExistent = path.join(tmpDir, 'no-forge-here');
    const result = await isExecutorRunning(nonExistent);
    expect(result).toBe(false);
  });
});

// ── Tasks table: pending -> running -> completed lifecycle ────

describe('task lifecycle via DB functions', () => {
  test('pending task can be claimed (pending -> running)', () => {
    const db = getTestDb();
    const now = new Date().toISOString();
    db.run(
      `INSERT INTO tasks (id, command, status, cwd, stdout, stderr, params, createdAt, updatedAt)
       VALUES ('task-lifecycle-01', 'forge run', 'pending', '/repo', '[]', '[]', '{}', ?, ?)`,
      [now, now],
    );

    const claimed = claimTask(db, 'task-lifecycle-01', process.pid);
    expect(claimed).toBe(true);

    const row = getTaskById(db, 'task-lifecycle-01');
    expect(row!.status).toBe('running');
    expect(row!.pid).toBe(process.pid);
    db.close();
  });

  test('completed tasks are excluded from getPendingTasks', () => {
    const db = getTestDb();
    const now = new Date().toISOString();
    // Insert a completed task
    db.run(
      `INSERT INTO tasks (id, command, status, cwd, stdout, stderr, params, createdAt, updatedAt)
       VALUES ('task-completed', 'forge run', 'completed', '/repo', '[]', '[]', '{}', ?, ?)`,
      [now, now],
    );
    // Insert a pending task
    db.run(
      `INSERT INTO tasks (id, command, status, cwd, stdout, stderr, params, createdAt, updatedAt)
       VALUES ('task-still-pending', 'forge audit', 'pending', '/repo', '[]', '[]', '{}', ?, ?)`,
      [now, now],
    );

    const pending = getPendingTasks(db, 10);
    expect(pending.find(t => t.id === 'task-completed')).toBeUndefined();
    expect(pending.find(t => t.id === 'task-still-pending')).toBeDefined();
    db.close();
  });

  test('stale task cleanup marks old running tasks as failed', () => {
    const db = getTestDb();
    const staleTime = '2020-01-01T00:00:00.000Z';
    db.run(
      `INSERT INTO tasks (id, command, status, pid, cwd, stdout, stderr, params, createdAt, updatedAt)
       VALUES ('task-stale-exec', 'forge run', 'running', 1234, '/repo', '[]', '[]', '{}', ?, ?)`,
      [staleTime, staleTime],
    );

    markStaleTasks(db, 60 * 60 * 1000); // 1 hour TTL

    const row = getTaskById(db, 'task-stale-exec');
    expect(row!.status).toBe('failed');
    db.close();
  });
});

// ── MCP command queue pattern: pending status on insert ──────

describe('MCP command queue insert pattern', () => {
  test('insertTask creates task with pending status (queue model)', () => {
    const db = getTestDb();
    const now = new Date().toISOString();
    db.run(
      `INSERT INTO tasks (id, command, description, specPath, status, cwd, stdout, stderr, params, createdAt, updatedAt)
       VALUES ('task-mcp-queue', 'forge run', 'implement feature', 'specs/feature.md', 'pending', '/repo', '[]', '[]', '{}', ?, ?)`,
      [now, now],
    );

    const row = getTaskById(db, 'task-mcp-queue');
    expect(row!.status).toBe('pending');
    expect(row!.specPath).toBe('specs/feature.md');
    db.close();
  });

  test('task params column stores executor dispatch parameters', () => {
    const db = getTestDb();
    const params = { specPath: 'specs/auth/', model: 'opus', extraArgs: ['--fix'] };
    const now = new Date().toISOString();
    db.run(
      `INSERT INTO tasks (id, command, status, cwd, stdout, stderr, params, createdAt, updatedAt)
       VALUES ('task-params-check', 'forge audit', 'pending', '/repo', '[]', '[]', ?, ?, ?)`,
      [JSON.stringify(params), now, now],
    );

    const row = getTaskById(db, 'task-params-check');
    const parsed = JSON.parse(row!.params) as typeof params;
    expect(parsed.specPath).toBe('specs/auth/');
    expect(parsed.model).toBe('opus');
    expect(parsed.extraArgs).toEqual(['--fix']);
    db.close();
  });
});

// ── Buffer management: last N lines retained ─────────────────

describe('stdout buffer management (MAX_BUFFER_LINES = 50)', () => {
  test('stores up to 50 lines in stdout JSON array', () => {
    const db = getTestDb();
    const now = new Date().toISOString();
    db.run(
      `INSERT INTO tasks (id, command, status, cwd, stdout, stderr, params, createdAt, updatedAt)
       VALUES ('task-buf', 'forge run', 'running', '/repo', '[]', '[]', '{}', ?, ?)`,
      [now, now],
    );

    // Simulate buffer with exactly 50 lines
    const lines = Array.from({ length: 50 }, (_, i) => `line ${i + 1}`);
    db.run('UPDATE tasks SET stdout = ? WHERE id = ?', [JSON.stringify(lines), 'task-buf']);

    const row = getTaskById(db, 'task-buf');
    const stdout = JSON.parse(row!.stdout) as string[];
    expect(stdout.length).toBe(50);
    expect(stdout[0]).toBe('line 1');
    expect(stdout[49]).toBe('line 50');
    db.close();
  });

  test('tasks table can store and retrieve empty stdout', () => {
    const db = getTestDb();
    const now = new Date().toISOString();
    db.run(
      `INSERT INTO tasks (id, command, status, cwd, stdout, stderr, params, createdAt, updatedAt)
       VALUES ('task-empty-buf', 'forge run', 'pending', '/repo', '[]', '[]', '{}', ?, ?)`,
      [now, now],
    );

    const row = getTaskById(db, 'task-empty-buf');
    const stdout = JSON.parse(row!.stdout) as string[];
    expect(stdout).toEqual([]);
    db.close();
  });
});

// ── Executor PID file lifecycle ───────────────────────────────

describe('executor PID file lifecycle', () => {
  test('PID file is written and readable', async () => {
    const pidPath = path.join(tmpDir, '.forge', 'executor.pid');
    await fs.writeFile(pidPath, String(process.pid));

    const content = await fs.readFile(pidPath, 'utf-8');
    expect(parseInt(content.trim(), 10)).toBe(process.pid);
  });

  test('PID file deletion makes isExecutorRunning return false', async () => {
    const pidPath = path.join(tmpDir, '.forge', 'executor.pid');
    await fs.writeFile(pidPath, String(process.pid));
    expect(await isExecutorRunning(tmpDir)).toBe(true);

    await fs.unlink(pidPath);
    expect(await isExecutorRunning(tmpDir)).toBe(false);
  });
});
